mapper.select:
SELECT HE.PERSON_ID, HE.EMPID, HE.LOCAL_NAME, GET_DEPT_NAME(HE.DEPTNO, #{lang, jdbcType=VARCHAR}) AS DEPT_NAME, GET_GLOBAL_NAME(HE.POST_GRADE_NO, #{lang, jdbcType=VARCHAR}) AS POSITION_NAME, HE.EMP_TYPE_CODE, SUM(NVL(T.NORMAL_WORK / NVL(NULLIF(T.SHIFT_LENGTH, 0), 8), 0)) AS NORMAL_WORK, SUM(NVL(T.LATE_ARRIVE, 0) + NVL(T.EARLY_LEAVE, 0) + NVL(T.GO_OUT, 0)) AS LATE_EARLY_GO_TOTAL
, SUM(NVL(T.${itemId}, 0)) AS ${itemId}
FROM AR_EMP_DAY_TOTAL T JOIN HR_EMPLOYEE HE ON HE.PERSON_ID = T.PERSON_ID AND HE.CPNY_ID = #{cpnyId, jdbcType=VARCHAR} WHERE T.CPNY_ID = #{cpnyId, jdbcType=VARCHAR} AND T.PERSON_ID NOT LIKE '1111%' /* Loại bỏ nhân viên giả lập dùng cho chấm công thủ công */
AND T.DATE_STR >= #{startDate, jdbcType=VARCHAR}
AND T.DATE_STR <= #{endDate, jdbcType=VARCHAR}
AND ( UPPER(HE.EMPID) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' OR UPPER(HE.LOCAL_NAME) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' )
AND INSTR(',' || #{deptNos, jdbcType=VARCHAR} || ',', ',' || HE.DEPTNO || ',') > 0
AND HE.EMP_TYPE_CODE = #{empTypeCode, jdbcType=VARCHAR}
GROUP BY HE.PERSON_ID, HE.EMPID, HE.LOCAL_NAME, HE.DEPTNO, HE.POST_GRADE_NO, HE.EMP_TYPE_CODE ORDER BY HE.EMPID

SELECT TO_CHAR(D.PK_NO) AS PK_NO, D.PERSON_ID, HE.EMPID, HE.LOCAL_NAME, D.SHIFT_NO, GET_GLOBAL_NAME(D.SHIFT_NO, #{lang, jdbcType=VARCHAR}) AS SHIFT_NAME, D.AR_DATE_STR, D.ITEM_NO, GET_GLOBAL_NAME(D.ITEM_NO, #{lang, jdbcType=VARCHAR}) AS ITEM_NAME, TO_CHAR(D.FROM_TIME, 'HH24:MI') AS FROM_TIME_STR, TO_CHAR(D.TO_TIME, 'HH24:MI') AS TO_TIME_STR, TO_CHAR(D.QUANTITY) AS QUANTITY FROM AR_DETAIL_HTSV D, HR_EMPLOYEE HE WHERE HE.PERSON_ID = D.PERSON_ID AND D.PERSON_ID = #{personId, jdbcType=VARCHAR} AND D.ITEM_NO = ( SELECT AI.ITEM_NO FROM AR_ITEM AI WHERE AI.ITEM_ID = #{itemId, jdbcType=VARCHAR} AND ROWNUM = 1 )
AND D.AR_DATE_STR >= #{startDate, jdbcType=VARCHAR}
AND D.AR_DATE_STR <= #{endDate, jdbcType=VARCHAR}
ORDER BY D.AR_DATE_STR
